            except:
                pass

        # Wait for processes to close
        gone, alive = psutil.wait_procs(vs_processes, timeout=10)

        # Force kill if still alive
        for proc in alive:
            try:
                proc.kill()
            except:
                pass

        time.sleep(2)

        # Restart Visual Studio instances with fresh environment
        if vs_exes:
            print("Restarting Visual Studio with fresh environment from registry...")

            for exe in set(vs_exes):  # Remove duplicates
                try:
                    # Use ShellExecuteW to launch VS - it reads fresh environment from registry
                    # This is better than subprocess.Popen which inherits current process environment
                    result = ctypes.windll.shell32.ShellExecuteW(
                        None,           # hwnd
                        "open",         # operation
                        exe,            # file
                        None,           # parameters
                        None,           # directory
                        1               # show command (SW_SHOWNORMAL)
                    )

                    # ShellExecuteW returns > 32 on success
                    if result > 32:
                        print(f"  Started: {exe}")
                    else:
                        print(f"  Error starting {exe}: ShellExecute returned {result}")
                except Exception as e:
                    print(f"  Error starting {exe}: {e}")

            print("\nVisual Studio restarted with fresh environment variables from registry.")
            print("Note: VS Code and other apps may need manual restart to see new environment.")

            # Offer to restart Explorer for system-wide refresh
            print("\nFor VS Code and other apps to see changes without manual restart:")
            restart_explorer()
    else:
        print("\nSkipping VS restart. You'll need to manually restart applications.")
        print("\nAlternatively, restart Explorer to refresh environment for all applications:")
        restart_explorer()

def main():
    # Check for admin privileges and relaunch if needed
    if not run_as_admin():
        return

    print("Available Sites:")
    sites = [f.split(".reg")[0] for f in os.listdir(REG_FOLDER) if f.endswith(".reg")]

    if not sites:
        print("No .reg files found.")
        return

    for idx, site in enumerate(sites, 1):
        print(f"{idx}. {site}")

    choice = input("Select a site (enter number or name): ").strip()

    if choice.isdigit():
        choice = int(choice)
        if 1 <= choice <= len(sites):
            site = sites[choice - 1]
        else:
            print("Invalid selection.")
            input("\nPress Enter to exit...")
            return
    else:
        site = choice

    if site in sites:
        success = import_reg_file(site)
        if success:
            # Verify the changes were applied
            verify_environment_variable("BeFirst:Site")
            refresh_environment()
            restart_visual_studio()
        else:
            print("\nFailed to import registry file. Environment not changed.")
            input("\nPress Enter to exit...")
    else:
        print("Invalid site name.")
        input("\nPress Enter to exit...")

def verify_environment_variable(var_name="BeFirst:Site"):
    """Verify that an environment variable was set correctly."""
    try:
        import winreg
        # Check HKEY_LOCAL_MACHINE\SYSTEM\CurrentControlSet\Control\Session Manager\Environment
        key = winreg.OpenKey(
            winreg.HKEY_LOCAL_MACHINE,
            r"SYSTEM\CurrentControlSet\Control\Session Manager\Environment",
            0,
            winreg.KEY_READ
        )
        try:
            value, _ = winreg.QueryValueEx(key, var_name)
            winreg.CloseKey(key)
            print(f"\nVerification: {var_name} = {value}")
            return True
        except WindowsError:
            winreg.CloseKey(key)
            print(f"\nWarning: Could not find {var_name} in registry")
            return False
    except Exception as e:
        print(f"\nWarning: Could not verify environment variable: {e}")
        return False

def refresh_environment():
    """Broadcast environment variable changes to running applications."""
    try:
        HWND_BROADCAST = 0xFFFF
        WM_SETTINGCHANGE = 0x1A
        SMTO_ABORTIFHUNG = 0x0002

        # Use SendMessageTimeout for more reliable broadcasting
        result = ctypes.c_long()
        ctypes.windll.user32.SendMessageTimeoutW(
            HWND_BROADCAST,
            WM_SETTINGCHANGE,
            0,
            "Environment",
            SMTO_ABORTIFHUNG,
            5000,  # 5 second timeout
            ctypes.byref(result)
        )
        print("Environment variables broadcast to running applications.")
    except Exception as e:
        print(f"Error refreshing environment variables: {e}")

if __name__ == "__main__":
    main()
